/**
 * @summary List schedule conflicts for a month
 */
export const ListConflictsQueryParams = zod.object({
  year: zod.coerce.number().optional(),
  month: zod.coerce.number().optional(),
});

export const ListConflictsResponseItem = zod.object({
  date: zod.string(),
  type: zod
    .string()
    .describe(
      "Type of conflict: side_no_rest, duplicate_assignment, missing_duo",
    ),
  description: zod.string(),
  duoId: zod.number().nullish(),
  duoName: zod.string().nullish(),
});
export const ListConflictsResponse = zod.array(ListConflictsResponseItem);

